const defaultResolvePath = require('./resolve-path');

module.exports = function mapPathString(nodePath, state) {
  if (!state.types.isStringLiteral(nodePath)) {
    return;
  }

  const resolvePath =
    state.normalizedOpts.customResolvePath || defaultResolvePath;

  const modulePath = resolvePath(
    nodePath.node.value,
    state.file.opts.filename,
    state.opts,
  );

  if (!modulePath || nodePath.node.pathResolved) {
    return;
  }

  nodePath.replaceWith(state.types.stringLiteral(modulePath));
  nodePath.node.pathResolved = true;
};
